-- Create mentors table
CREATE TABLE IF NOT EXISTS public.mentors (
  id SERIAL PRIMARY KEY,
  name TEXT NOT NULL,
  firm TEXT,
  expertise TEXT,
  focus_areas TEXT,
  ag_expertise TEXT,
  experience TEXT,
  linkedin TEXT,
  startups_worked_with TEXT,
  compensation TEXT,
  available TEXT DEFAULT 'Yes',
  country TEXT DEFAULT 'US',
  country_detail TEXT,
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now()
);

-- Enable RLS
ALTER TABLE public.mentors ENABLE ROW LEVEL SECURITY;

-- Allow anyone to read mentors
CREATE POLICY "Mentors are viewable by everyone" ON public.mentors
  FOR SELECT USING (true);

-- Allow admins to manage mentors
CREATE POLICY "Admins can manage mentors" ON public.mentors
  FOR ALL USING (
    EXISTS (SELECT 1 FROM public.profiles WHERE id = auth.uid() AND role = 'admin')
  );


