INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Annalisa Williams', 'AgNexus Consulting', 'Supporting Ag Innovation from Research to Revenue: Revenue generating market application of science - market niche development, value proposition, strategic market alliances, regulatory strategy, IP,', 'Microbial, alternative chemistries, fertilizer, biocontrol, metabolite, plant based extracts', 'Specialty Crop (fruit/nut/veg)', '15+ years of experience in sales and marketing in bioag / agtech. Co-founder and Principal consultant at AgNexus Consulting providing strategy on market fit and niche development for pre-commercial technologies to direct applied research. Integration of market driven research into strategic product positioning and regulatory strategy to support overall business objectives / fundraising efforts. B2B collaborations with major manufacturers including private label, formulation, investment and aquisition.', '', 'NDAs in place for most clients. Most of our clients are', 'Cash & Equity', 'Yes', 'US', 'US');
