INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Anthony Padgett', 'Twenty Two North', 'Ag tech broadly, with specific interest in seed technology, robotics, soil biometrics, trait discovery, and production agriculture.', 'Seed technology, robotics, soil biometrics, trait discovery, and large scale production agriculture.', '', 'Founder and former CEO of VoloAgri (now AXIA, vegetable seed), Co-Managing Director of the Monsanto Seed Group (row crops), numerous M&A transactions in ag related companies in over 30 countries; Director at Verdant Partners; partner in large corporate law firm focusing on international transactions; owner of beef production farm in Upstate New York. Have lived and worked in ag tech in USA France, Spain, Singapore and the Netherlands.', 'https://www.linkedin.com/in/anthony-padgett-572a5b25', 'Numerous in all of the categories noted above in focus areas.', 'Equity', 'Yes', 'US', 'usa');
