INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Baha Sadduk', 'AgTech Confidential', 'Inventory management, Regulatory compliance, transportation and logistics (including OS) for produce and machinery/equipment, Developing comprehensive training programs, Program design, Ensuring OSHA compliance, Establishing supplier verification programs, Food Safety Programs, Mock Audits with comprehensive analysis, Hazard assessments (field and manufacturing), Reviewing GMP and overseeing validation and verification processes, Leading project management initiatives, Implementing GS1 standards, Ensuring readiness for FSMA 204 regulations, Achieving GS1-128 compliance, Implementing safety programs (field and shop), Developing preventive maintenance programs, Crisis Management, Traceability Program, and Recall Readiness.', 'Tech/machinery compatibility assessment; program development and integration. Ensuring', 'Specialty Crop (fruit/nut/veg)', 'Over 23 years of work experience, from the field to retail. Including soil, seeds, growing, harvesting, cooling, transportation, quality control, audits, food safety. In the last 10 years I have been incredibly focused on supply and bloc chain development, consulting on numerous committees- including the FDA. Experience also extends to new tech/machinery development, marketing, sales, and facility set-up. ATC has two project managers on-board who also specialize in program assessments, program design, and sales.', 'https://www.linkedin.com/company/ag-tech-confidential', 'Muzzi Family Farms, Coastline Family Farms, and Axis Ag, Inc.', 'Cash & Equity', 'Yes', 'US', 'usa');
