INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Blair Swadley', 'Blair Swadley Law- Employment Advising', 'Human Resources and employment law. Hiring strategy, legal compliance with labor code and employee classification, wage & hour compliance, employee handbooks and policies, safety policies, employee performance coaching, workplace conflict resolution, termination, layoffs.', 'Employment Law & Human Resources', 'Specialty Crop (fruit/nut/veg)', 'Current VP of Human Resources and Legal Compliance for Advanced Farm Technologies. Practiced law handling employment, insurance and personal injury defense litigation prior to joining Advanced Farm. I am dedicated to finding the right balance for your company of mitigating legal risk while still maintaining the culture you want for your employees.', 'https://www.linkedin.com/in/blair-swadley-72b23231', 'Advanced Farm Technologies', 'Cash', 'Yes', 'US', 'USA- California');
INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Brad Fruth', 'Becks Hybrids', 'AgTech - IT background.  Product development, IT, value prop, and customer validation', 'Row Crop, IT, and Livestock (Swine)', 'Midwest crops (corn/soy)', '19 years of experience at an independent seed company focused on the convergence of agriculture and technology to provide a true return on investment to growers.  It has to be net not neat.  My family farms row crops and rwe aise hogs for a large packer in Indiana.', 'https://www.linkedin.com/in/brad-fruth-68429573', 'Mentor for multiple accelerators and startups in row crop and livestock sector.', 'Equity', 'Yes', 'US', 'Unknown');
