INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Brent Shedd', 'Ceres Innovation', 'Full-spectrum startup experience particularly with AI-oriented solutions. Strategy, Marketing, Leadership, Sales, Product Development, Fundraising', 'Artificial Intelligence, Automation, Manufacturing', 'Specialty Crop (fruit/nut/veg)', 'Founded multiple Artificial Intelligence companies. Former COO of Verdant Robotics and CEO of Stout Industrial Technology where I brought in CNH Industrial as a strategic investor and secured global distribution for Stout''s products through New Holland dealerships. Prior to that, CEO of an autonomous vehicle company in the aviation space. Currently running an AgTech startup in stealth mode.', 'https://www.linkedin.com/in/brentshedd', 'Under NDA', 'Open', 'Limited', 'US', 'Unknown');
INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Chandler Schmidt', 'Hovey Williams LLP', 'Intellectual property law, patent prosecution in electrical, software, and mechanical arts', 'Agricultural equipment and controls, including irrigation systems; communications systems; three-dimensional printing; electric motors and power generation', 'Midwest crops (corn/soy)', 'I help companies protect their innovations and navigate intellectual property risks.', 'https://www.linkedin.com/in/chandler-schmidt', 'I have helped many clients obtain patent protection for their inventions, helped them use other modes of IP proteciton, and have guided them through infringement risks and licensing.', 'Open', 'Yes', 'US', 'USA');
INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Charles Gentry', 'The National Institute of Agricultural Botany', 'Digital agriculture, artificial intelligence', 'Traditional Ag R&D (seeds and products), digital ag applications, crop modelling', 'Specialty Crop (fruit/nut/veg)', '13+ years working in agricultural research services (CRO) specialising in OSR/Canola and Potatoes, shifted into digital ag: drones, satellite/remote sensing with trials applications. Now supporting AgTech startups.', 'https://www.linkedin.com/in/charles-gentry-407b7411', 'See Barn4 membership page.', 'Equity', 'Yes', 'UK', 'UK');
INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Chris Hall', 'Consultant', 'AgTech growth, building customer operations/support, customer success, AI/ML/Data Science team building, CV/AI/ML Data Collection (image/sensor), GTM in global fruit and greenhouse markets,', 'customer operations, data collection and data science', 'Specialty Crop (fruit/nut/veg)', 'VP of Operations for FruitScout, building Customer Operations in North and South America. Buildout of customer data collection platform and protocols through data processing and ultimately data presentation to the customer. Inluded product development and model building for different growing systems and crops. Director of Technical Support for greenhouse tech startup iUNU, building out team to install iUNU systems to customer greenhouses and support operations. Included product development partnerships with product team.', '', 'FruitScout', 'Open', 'Yes', 'US', 'Canada/USA');
INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Cody Ruiz', 'Innovative Ag Consulting', 'Product development, Commercialization planning, Operations workflow, Data collection, commercialization and innovation', 'Product Development, Implementation, Value Proposition and Data Collection', 'Specialty Crop (fruit/nut/veg)', '5+ years working and managing operations for Ag Tech companies. Automation, Robotics, UAV data collection and precision input applications. I''ve ran equipment in all throughout California and Arizona and have a "boots on the ground" view of companies operations.', 'https://www.linkedin.com/in/cody-ruiz-529837164', 'Farmwise, Naio Technologies, Hummingbird Labs, GeoVisual Analytics', 'Open', 'Limited', 'US', 'USA');
INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Craig Ganssle', 'Farmwave', 'Artificial Intelligence, Start-Up, Product Development, Product Marketing, Value Propositioning, Leadership, Technology, Entreprenuership', 'AI, Agtech, Software, Hardware', '', '30 years in advanced technology. Entered agriculture by inviation and lead AI efforts in the industry starting in 2014. Multiple patens in AI AgTech, took product to market with value-add proposition post $1M revenue.', 'https://www.linkedin.com/in/cwganssle', 'Experience not with startups rather most major corporation in agriculture, dealer, and direct to farmers and through precision ag dealers and partners.', 'Open', 'Yes', 'US', 'USA with experience and connections in Europe, Canada, Brazil, Argentina, Australia.');
INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Dan Schultz', 'Schultz Collaborative', 'Category design, marketing strategy, helping companies think different.', 'I help companies across the agricultural spectrum to be different in the way they market and sell their product or service.', 'Midwest crops (corn/soy)', 'I serve as a fractional CMO and marketing advisor to a number of agtech companies, helping them to stop telling boring stories while selling world-changing innovations off technical spec sheets. I help companies stop droning on about improvement and start building their movement.', 'https://www.linkedin.com/in/danpschultz', 'Sentera, Arable, Advancing Eco Agriculture, AcreTrader', 'Cash & Equity', 'Yes', 'US', 'Unknown');
