INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Engin Anil', 'Consultant', 'Autonomy/automation, robotics, engineering team building and growth, engineering leadership, growth stage startups, Perception, SLAM, Localization, Mapping, Perception.', 'Engineering leadership', '', 'Delivered the 1st driverless AVs in the middle-mile segment in US and Canada.I ntegrated 1st Fleet Platform into AV powered logistics chains in US and Canada, enabling accurate, actionable metrics for environmental impact, and logistics reliability. Successful 1st launch of AMP Fusion Maps for Toyota’s millions of consumer vehicles. Introduced repeatable, scalable, productized development processes and roadmaps to produce frequent, planned, production-ready software. Built balanced teams of up to 40.', 'https://www.linkedin.com/in/ebanil', '', 'Open', 'Yes', 'US', 'Unknown');
INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Gaurav Bansal', 'AMG VENTURE PARTNERS', 'Venture Capital, Angel Investor, Fundraising from investors', 'Fundraising from angels and Venture Capital funds', '', 'Gaurav is a Tech Investor & Advisor (100+ startup investments globally), experience in venture capital & global growth accelerator program (35+ investments in 10 countries), investment banking (IPO/Private Equity deals worth ~US$2Bn) and technology consulting (business intelligence).', 'https://www.linkedin.com/in/gauravbansalventurecapital', '100+ startups across the US, Canada, LATAM, Eu, UK', 'Cash & Equity', 'Yes', 'US', 'Unknown');
INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Grant Bolton', 'Bolton et al', 'B2B Copywriting (content writing, white papers, case studies, sales copy, data storytelling) Ghostwriting (thought leadership articles, LinkedIn posts, presentations/pitch decks) PhD in entomology', 'Pest management, crop protection, biologicals, entomology', '', 'I am a B2B copywriter/ghostwriter with a PhD in entomology. My research was focused on trap design and chemical ecology. I have published several peer-reviewed articles. I currently work as a full-time writer, combining my research skills, creative and persuasive writing, and storytelling capabilities to help clarify your data and information into engaging stories.', 'https://www.linkedin.com/in/grant-bolton', 'Pivot Bio, Harpe BioHerbicide, Invasive Species Corporation', 'Cash', 'Yes', 'US', 'USA');
INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Grant Rickon', 'Rickon Consulting', 'Post-harvest product development, trial design and execution at grower, packer and retail levels, EU and UK retail. Operational implementation abroad and company structure.', 'Product Development/management, Company Structure, Trial Development, Diligence, Retail Engagement, International Operationalization', 'Specialty Crop (fruit/nut/veg)', 'I was an early member of a rapid growth startup which was valuead at $2B during my 8+ year tenure. I started in early product development in the lab as a research chemist and grew to lead equipment implementation into South America, Europe and South Africa. In addition, led commercial activities in EMEA with packers, exporters and retailers. I have led trial development work into the largest retailers in the UK and Europe working across the chain, have managed company restructures, and product development work from lab to commercialization.', '', 'Under NDA', 'Cash & Equity', 'Yes', 'US', 'USA, Europe and South Africa');
INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Heather Riden', 'UC Davis Western Center for Agricultural Health & Safety (WCAHS)', 'Occupational health and safety; human/technology interface in emerging technology applications; hazard identification; stakeholder engagement; community engagement', 'Human safety: opportunities to reduce injuries through agtech; identify unintended consequences that may lead to new safety hazards', 'Specialty Crop (fruit/nut/veg)', 'WCAHS is one of 12 agricultural health and safety centers in the U.S. established by the Centers for Disease Control and Prevention (CDC) and the National Institute for Occupational Safety and Health (NIOSH). Our mission is to improve the health and safety of agricultural workers in the west through innovative research, interactive trainings, and tailored outreach. We recognize AgTech as an important focus area and are interested in working with others to ensure safety remains at the forefront of the development and implementation of new technology.', 'https://www.linkedin.com/in/heatherriden', 'NA', 'Open', 'Yes', 'US', 'Unknown');
INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Heather Stiles', 'Cowboy Carbon, LLC / Alazan Asset Management, LLC', 'Beef cattle production, management, hedging and marketing, with a focus on verified beef programs (NHTC, NE3, GAP, AGA), genetics, and regenerative ranching/soil carbon.', 'Verification, Certification, Traceability, Soil Carbon, Genetics', 'Livestock / Dairy', '5th generation cattle rancher with over 30 years of experience in all aspects of beef production, from cow/calf to feedyard.Expertise in hedging and speculative futures trading. Experience auditing ranches in verified beef programs, ensuring compliance with strict standards for animal welfare, environmental sustainability, and food safety. Ability to bridge the gap between agtech and ranchers, providing ranchers with the tools and resources they need to make informed decisions about their businesses.', 'https://www.linkedin.com/in/heather-stiles-99b07517', 'Dolphin Capital Managment, Max Pay Gold', 'Cash & Equity', 'Yes', 'US', 'Unknown');
INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Igor Buchatskiy bucha66@gmail.com', 'TA Ventures', 'AgTech/FoodTech market fit/growth, large farm management, strategy, business development', 'General management, GTM, AI, robotics, early stage startups', '', 'Ex McKinsey/Bain consultant/CEO of a number of large farming enterprises (from 8,000 to 200,000 acres, animal husbandry/row crops/dairy/fruits/food production/co-founder of a food company/Venture Partner at the early stage VC fund', 'https://www.linkedin.com/in/igor-buchatskiy-54217a', 'The Hummingbird Technologies (UK)/ToolsVilla (India)/Conservis (USA)/Good Agriculture (USA)/Spilka (Ukraine)/Fitoscan (Ukraine)', 'Cash & Equity', 'Yes', 'US', 'USA - East Coast');
INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('James Pearce', 'Consultant', 'Microbial biological crop inputs  - biostimulants and biopesticides.  Most knowedgeablle on the technology but also production, including scale up, formulation and regulatory.', 'Microbial biopesticides for specialities, biostimulants for row crops (N and P).  Strengths / weaknesses of competitor technology.  Microbial discovery, optimizaton and screening.  Field tral design.  IP strategy.', 'Midwest crops (corn/soy)', '21 years in Ag Biotech,  from big (MON, BAYER, SYT) early stage (Cibus) to start ups (CSO at Boost Biomes).  Advisory roles on several Ag Bio start ups.', 'https://www.linkedin.com/in/james-pearce-21b99616', 'Confidential', 'Cash & Equity', 'Yes', 'US', 'Unknown');
INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Jamie Bacher  jamie.bacher@gmail.com', 'Huxley Project LLC', 'Consultant for investors, startup companies and partners; ad hoc / informal advising to startups.   Corporate and fundraising strategy; Technology strategy from discovery through to commercial-readiness; IP and regulatory strategy; Program management; Outsourced technology development.  Will the technoeconomics work commercially?  Biotech founders usually wait too long to figure this out. 2x startup founder, raised $20M, closed multiple deals with $B partners.', 'Ag biotech, synthetic biology, industrial biotech  Biopesticides, biocontrol agents, biostimulants, biofertilizers  Foodtech, precision fermentation, protein, cellular ag  Post-harvest crop protection', '', 'Biofuels / Industrial biotech: Sapphire Energy, Amyris/Total New Energies  Synbio: Pareto Biotechnologies, Sprint Synthesis  Ag biotech: Boost Biomes', 'https://www.linkedin.com/in/jbacher', '', 'Open', 'Yes', 'US', 'USA');
INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Jason Mellow', 'Axis Ag, Inc. https://www.axisag.farm', 'Market entry, Equpment commercilization, value proposition strategy, operations planning and creation, asset acquisition, research, operations management, GTM strategy, employee hiring, field iteration, data collection, AI/ML data management, Hardware/Software/Backend engineering, harvesting, etc.', 'Operations, multi-market commercialization, data management, start-up to grower relations, customer management, strategy. Market Entry Consulting.', 'Specialty Crop (fruit/nut/veg)', 'We have extensive experience with creating and managing commercialized, service-based operations for start-ups and established companies. Most recently we created FarmWise''s operational program, created the operational culture, and established/trained the FarmWise Operations Management Team.  We have managed hundreds of employees operating in multiple markets, in multiple states.  We currently operate in California, Arizona, and the Pacific Northwest.  We are able to provide engineering expertise related to hardware, software, AI/ML, backend, and UI/UX.  We work with an extensive network of growers and independent consultants throughout the Western U.S.  We are a team that combines agricultural and engineering experience to produce fantastic results.  We like to find solutions to challenges.  https://www.axisag.farm', 'https://www.linkedin.com/company/axis-ag-inc', 'Niqo Robitics, FarmWise Labs, Ecorobotix, and several others under an NDA.', 'Open', 'Yes', 'US', 'Unknown');
INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Jess Pattison', 'Dirt Lab', 'Venture Strategy, Product strategy & validation, Product development, Capital raising', 'Early-Stage across food and fibre. Our core pillars we hope to enable through partnering are; Affordable and ethical labour, Transitions to best practice management, Resilient Supply Chains, Improved Decision Making, Resilient Regions', '', '10 years of experience across consulting and startups in a range of industries, with 4+ years spent working in the mining sector on various technology and automation projects. For the last few years, I''ve been focused on taking ventures/products from early concept to validation and onto MVP or PMF.  Our Dirt Lab team (part of the Josephmark group) as a whole has a number of years of experience in research commercialisation and the venture studio model.', 'https://www.linkedin.com/in/jessicapattison', 'In Ag for DL: Worms Down Under, Monty, Pandaemonium + a few under NDA Broad spectrum of startups/clients see: https://pitch.com/public/a5b85980-c6ff-4bf4-a64a-b6cfbad32c71', 'Equity', 'Yes', 'US', 'Australia');
INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Joe Hubert', 'Consultant', 'Application requirements management, application design, data modeling.', 'Software solution management', '', 'Software developer, architect, analyst and technical manager experienced with logical application design.', 'https://www.linkedin.com/in/joehubert', 'Logical Design Solutions, Vertek, Synchronoss, Formity, Avotus, OneCall Manage', 'Cash', 'Yes', 'US', 'USA');
INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Joel Lipsitch', 'Blair Road Consulting', 'Comercialization of AgTech with a focus on inputs and hardware', 'Commercial strategy and execution including product development, product marketing, route-to-market, business development, and sales. Customers include startups and VC/PE investors.', 'Specialty Crop (fruit/nut/veg)', '', '', 'Under NDA (approximately 6 clients/year. Startup clients range from pre-revenue to Series C/D.', 'Cash & Equity', 'Yes', 'US', 'USA');
INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Joel Perez', 'Vine Advancement L.L.C.', 'Viticulture (wine grapes), varietal differences, soil and vine nutrients, agronomy, remote sensors, technological integration, data translation,  wine-growing logistics,', 'Wine grapes, weather and farm monitoring systems, drone imaging, wine production logistics, grant writing, business modeling.', 'Specialty Crop (fruit/nut/veg)', 'I am a 10 year veteran with extensive experience in communications and logistics, having overseen operations using technoligy in three countries simultaneuously.  As a wine grape expert and former Direct of Viticulture, I rewrote the curriculum for the Walla Walla Institute of Enology and Viticulture, while running the vineyards  This included the integration of nutrients, ag technology, and seminars for industry members and scientists.  I directed and assistend with industry projects evaluating the utility of ag tech in wine grapes in Washington state, Colorado, Idaho, and Australia.  I have a B.S. in Integrated Plant Science with a minor in Biology, a M.S. in Horticulture with and emphasis on late season ripening and biochemistry, and studied at the School of Engineering at the University of Purpan in Toulouse, France.', 'https://www.linkedin.com/in/joel-perez-b49594207', 'Fruition Sciences, The Yield (Australia), John Deere', 'Cash & Equity', 'Yes', 'US', 'Unites States of America');
INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('John Bailey', 'Top 10 Produce LLC & Alternative Dispute Resolution APC', 'Small Farm Traceability and Beef Supply Chain Traceability', 'Traceability, Food Safety, Meat Processing', 'Specialty Crop (fruit/nut/veg)', 'Working with successfully funded projects through NIFA''s National Integrated Food Safety Initiative and the Small Business Innovation Research Program in Produce Traceability Compliance and Small Beef Traceability Pilot systems using QR codes and GS1 interoperability.  I have experience working with produce safety rules at the small farm level and in USDA regulations for small USDA inspected beef businesses serving smaller local ranches.', 'https://www.linkedin.com/in/johnleonardbailey', 'Under NDA with Top 10 Produce LLC or Attorney-Client confidential through my Law Corporation', 'Open', 'Limited', 'US', 'Unknown');
INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Jorgelina Lezaun', 'AgriConsult Latam', 'Softanding & Internationalisation process / Latin America & Caribbean / US EU Asia regions, -Strategic Marketing Plans & Business Model development;  Outsourcing services (HR, R&D, Product development, Registration, finance, accounting, legal) - Process Implementation, Design & Monitoring - RSE - Sales channels design & commercialization', 'Inputs (Biologicals, chemicals) Fertilisers Food Safety ODS Techs Automation', 'Specialty Crop (fruit/nut/veg)', 'More than 15 years of work & expertise at DuPont Crop Protection Southern Cone (business areas Marketing, Sales, RSC, R&D) General Manager Outsourced of Provivi US - responsible to establish their 1st global subsidiary as biologicals manufacturers / CEO & founder of AgriConsult Latam /  www.agriconsult-latam.com', 'https://linkedin.com/in/jorgelinalezaun', 'Provivi US, AgriConsult Latam, FFO, Alquimia', 'Open', 'Yes', 'US', 'Unknown');
INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Josh Ruiz', 'Innovative Ag Consulting', 'Ag-Tech product development, implementation, and analysis from the persepective of a grower, as I am also a grower', 'Value proposition, implementation, and execution, as well as connecting the right people for the product.', 'Specialty Crop (fruit/nut/veg)', 'With 20+ years in the growing and harvesting of fresh vegetables, I have seen a lot of tech, and implemented a lot of tech, which gives me a unique perspective. My value to start-ups is thru real world experience, and knowing what can and can not happen in the field. In addition to this, I am able to help Ag Tech companies with approch, so that their first impression with the grower/farmer is right.', 'https://www.linkedin.com/in/nicholas-ruiz-6643b29', '', 'Open', 'Limited', 'US', 'Unknown');
INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Kaija K. Janson', 'Consultant', 'Early stage startup advisory / mentoring: Product-market fit, Value proposition, Commercialization, Strategic business development', 'Biotech, Agtech, Foodtech, FMCG', 'Specialty Crop (fruit/nut/veg)', 'Combined experience of corporate world (Microsoft, Procter&Gamble, NielsenIQ; being responsible for regional EMEA and global work in fields of sales & marketing, innovations, partnerships, business development and   processes/operations as well as leading cross-border multi-stakeholder teams), international organizations (holding several leadership roles in ECR) and startups (running/ advising startups and being a partner evaluator in EIT Food program, Latvian Investment and Development Agency and other).', 'https://www.linkedin.com/in/kaija-k-janson-6ab4983', 'EIT Food startups', 'Cash & Equity', 'Yes', 'EU', 'Europe (based in Latvia)');
INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Kelly Smith', 'Kalmia Consulting, LLC', 'R&D Strategy and Planning, Commercialization and scale-up Intellectual property Regulatory strategy Mentoring and professional development for technical founders Feedback and performance assessment coaching Investment pitch deck review and feedback Fermentation process development and scale-up Formulation development of biological products Tech transfer to manufacturing Effective communication between technical and business teams Experience from product concept through commercial manufacturing', 'Biological and biochemical inputs including biopesticides, biofertilizers, biostimulants', 'Specialty Crop (fruit/nut/veg)', 'Multiple ag and industrial biotech companies, including successful exit from Pasteuria Bioscience when sold to Syngenta. Handled everything from early technology development through product and process development, regulatory and manufacturing.  Lead scientist and team leader at AgBiome, Joyn Bio and VP of R&D at DMC Biotechnologies. Built high performing teams and lead the development of company culture.', 'https://linkedin.com/in/drkssmith', 'Pasteuria Bioscience, AgBiome, Joyn Bio, DMC Biotechnologies, Switch Bioworks, Robigo', 'Cash', 'Yes', 'US', 'USA, some experience with import/export of biological products');
