INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Lee McAvoy', 'JP Morgan', 'Early-stage financing/captial raising, debt/equity capital markets, startup advisory services, M&A, project finance, equipment finance, treasury services, renerative/sustainable agriculture, IP', 'AgTech, Commodities, Consumer Goods, Renewable Energy, Battery Tech, Clean Mobility', '', 'Vice President on JP Morgan''s Green Economy Banking team. My background is in investment banking, private equity, venture capital, and corporate finance where I''ve focused on AgTech, food & beverage, consumer goods, as well as renewable energy. I have a wide range of experience working with everything from some of the world''s largest corporations (inlcduing the ABCD agricultural firms), all the way to start-ups across North America and Sub-Saharan Africa', 'https://www.linkedin.com/in/leemcavoy', 'Large range of companies from ADM, Bunge, Cargill, Ingredion, General Mills, Coca-Cola, etc., to startups such as Kate Farms, Gotham Greens, Plantible, Beyond Meat, Oatly, etc.', 'Pro Bono', 'Yes', 'US', 'USA/Canada; Broad experience across North America and Sub-Sarahan Africa');
INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Lisa Johnson', 'Consultant', 'Food loss, food waste, agricultural supply, federal funding, startup strategy, surplus food, farming perspective, sustainability', 'Measurement, data, analysis', 'Specialty Crop (fruit/nut/veg)', 'Lisa K. Johnson, PhD is a leader in on-farm food loss research, whose projects focus on in-field measurement, estimation and analysis of food loss, in fruit and vegetable crops. She provides collaborators with technical assistance and protocols for reducing food loss, in accordance with UN SDG 12.3. She is a strategic and research partner to the U.S. EPA, Society of St. Andrew, Boston Area Gleaners, ReFED, WWF, WRI, UpRoot Colorado, the Consortium for Innovation in Postharvest Loss & Food Waste Reduction, and numerous startups. Dr. Johnson has authored chapters in The Economics of Food Loss in the Produce Industry and Routledge Handbook of Food Waste. She has spoken to dozens of audiences, including the Consumer Goods Forum and the European Commission, has been quoted in media outlets such as Forbes and Huffington Post, and has led proposal development for over $4M in awarded funding. Working in specialty crops since 1999, Dr. Johnson considers herself a lifelong horticulturist.', 'https://www.linkedin.com/in/lisa-k-johnson', 'NDAs, I have collaborated with and advised startups who are starting to source surplus fruit and vegetable crops in order to produce new consumer products.', 'Cash & Equity', 'Yes', 'US', 'US');
INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Luca Matteoli', 'VELARIS CAPITAL  Advisor', 'Business strategy, M&A advisory, financial modeling, corporate finance, and growth acceleration strategies. Specific focus on strategy, sales, and capital raising for scaling businesses. Corporate Finance Advisory. I advise clients in both buy-side, sell-side and capital raise (pre-see to Series C) transactions ranging from public auctions to tailored one-on-one situations.  I serve my clients by connecting networks, developing strategic dialogues, recommending solutions and providing advisory services on the execution of event-related transactions.', 'Inputs (biological/chemical), regenerative agriculture, sustainable farming practices, biofertilizers, and yield improvement strategies. Ag Tech, Robotics, Grains, Oilseeds and Sugar, Animal Health', 'Specialty Crop (fruit/nut/veg)', 'Previously Executive Director at Rabobank New York and Rotterdam with significant exposure to agribusiness and food sectors. 13+ years in corporate finance and M&A advisory with a track record in agribusiness sectors. Lately working with biofertilizer company to develop a Seed, Series A/B capital raise strategy to expand sales and market presence in the US and EU. Experience in M&A middle-market transactions $50-1500m, strategic planning, and financial advisory.', 'https://www.linkedin.com/in/lucamatteoli', 'Extensive number of transactions and capital raises throughout the years of investment banking', 'Cash & Equity', 'Yes', 'US', 'USA  EU');
INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Lucas Buchmiller', 'Climate FieldView / Bayer Crop Science', 'Expert in machine data collection, working with small equipment manufacturers to large OEMs. Mobile app development. Experience in the transition from start up to large company integration. Involved in government relations and international standards groups. Co-operate a 300 acre row crop farming operation. Commercial experience in working with go to market strategies globally and managing  smaller regional sales team. Highly focused on the end use cases of farmers and have worked on value chain projects for sustainability and traceability efforts.', 'Farm management systems/ Ag equipment/ on farm hardware integrations / mobile application development', 'Midwest crops (corn/soy)', 'Worked at an OEM dealership and started a digital ag program. Worked as a product support before transitioning into product management. Have been in this space for almost 10 years. More recently working directly with government and international standards groups', 'http://linkedin.com/in/lucas-buchmiller', 'N/A', 'Open', 'Yes', 'US', 'United States in the Midwest');
