INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Matthew Hoffman', 'Driscoll''s, Independant Consultant', 'Driscoll''s capacity: Scout, select, trial, and deploy agtech solutions that address our priori challenges in areas of 1) pest and disease, 2) labor automation, and 3) pollination.  Cnsultant capacity: Hourly consultant in areas of winegrapes and specialty crops generaly, with broad range of experience including dudiligence advising (e.g. farmer BS meter), designing commercial-scale trials, product-market fit, industry introductions, pricing and sales models, and general lending of agricultural system expertiese.', 'Berries, winegrapes, specialty crops, grower economics, farm operations, communications, knowldge management, digital transformation, pest and disease management, field automation, grower education and research program development, project and program management, strategic planning for technology, organizational maturity', 'Specialty Crop (fruit/nut/veg)', 'I come from a multi-generational farming family. My degrees are in agricultural production and rural sociology. I have decades of professional experience working with agricultural innovation from the acemdmic, public, and commercial persopective. I have helped several startups overcome their challenges at whatever stage they are in.', 'https://www.linkedin.com/in/matthew-hoffman-387b8b9b', 'TRIC Robtoics, Agragene, BigSis, BloomX, CleanWorks', 'Cash', 'Yes', 'US', 'USA');
INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Michael Macolino', 'Recode Ventures / Independent Advisor', 'Market entry into Australian / US / Canada  Commercialisation and channel partnership strategy Investment and growth strategy', 'Seed to Series A Companies planning international growth.  Software, Robotics, CEA, MRV technologies', 'Specialty Crop (fruit/nut/veg)', 'Previously the Managing Director for APAC at SVG Ventures Thrive and Director for AgriFood tech at BDO. Michael privately advises startups and organisations across the global AgriFood innovation eco-system. Michael started out as an entrepreneur at the age of 21 and built 5 businesses over a 15 year period.', 'https://www.linkedin.com/in/michaelmacolino', 'Pairtree  Bygen FieldIn Lyro Robotics  Fresh Supply Co Harrington Seed Destructor', 'Equity', 'Yes', 'US', 'Australia');
INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Michael Ott', 'Lutra Investments', 'Business foundation, go to market strategy, fundraising', 'Ag robotics, gene editing, seed treatment, drones, application technology, seed traits', 'Midwest crops (corn/soy)', 'Founding CEO at Rantizo and Cquesta. I have built 3 businesses from an idea to an actual entity. Rantizo is now operating in 35 states. We initially focused on commodity crops and now have a large portfolio in specialty as well. At Cquesta I led a gene editing effort to generate carbon credits for farmers. I have raised over $180M in my career. Before that I worked in corporate VC and founded a seed treatment business in India. I have international experience in Brazil, India, Ukraine, Ireland, Canada and El Salvador', 'https://www.linkedin.com/in/michael-ott-362a2', 'Multiple companies through the AgLaunch Accelerator program as well as confidential customers through Context Network and Guidepoint. Typical clients are seed stage through Series A looking for initial advice as well as go to market and fundraising. I''ve also been a mentor at the Iowa Startup Accelerator', 'Cash & Equity', 'Yes', 'US', 'USA');
INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Micki Seibel', 'Farmhand Ventures & Radicle Growth', 'Go to market strategy, fundraising, company building, venture investment, product management, software and technical engineering, cybersecurity, Board of Directors, corporate governance, board management & construction', 'Early stage company building: Pre-seed to Series B', 'Specialty Crop (fruit/nut/veg)', 'Chief Digital Officer, Unfold Bio, Board of Directors of Fieldwork Robotics, 5 years of AgTech venture capital experience (Radical Growth, Farmhand Ventures) + 20 years of company and product building experience in Silicon Valley (startups and large companies). Served on Board of Directors of Boost Biomes. 3 startup exits.', 'https://www.linkedin.com/in/mickiseibel', 'As an Advisor: Swarm Technologies (acquired by SpaceX), Wexus, Ripe.io, ImpactVision (acquired by Apeel), Mast Reforestation, zTractor, Beyond The Dome. As a Board Member: Boost Biomes, Fieldwork Robotics.', 'Cash & Equity', 'Yes', 'US', 'Unknown');
