INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Molly Stanek', 'EcoAgTech', 'Early to mid stage startup strategy and advisory services. Fractional CEO and COO - helping to cut the painful parts of the learning curve.', 'Operations (huge culture nerd), Technology development and strategy, CEA (vertical and greenhouse, incl. aquaponic), food manufacturing, USDA Organic', 'Specialty Crop (fruit/nut/veg)', 'GM at Plenty, SVP at Sensei Ag, VP at Superior Fresh. Provided expert due diligence on $300MM in CEA funding. 15 years experience in senior and executive leadership roles.', 'https://www.linkedin.com/in/mollystanek', 'Hippo Harvest, Homeboy Industries, Myconaut', 'Open', 'Yes', 'US', 'US');
