INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Nathan Faleide', 'Black Hammer LLC (Consulting), Boundri, Satshot, Easy Observations (Newsletter)', 'Ag software development (leadership, product management, sales, marketing, strategy), Remote Sensing and Earth Observation, Farming', 'AgTech and Imagery, sucker for Entrepenurs', 'Midwest crops (corn/soy)', '25+ years in the Agriculture Industry. Grew up on a farm in central North Dakota along with my family''s company Satshot, which was one of the earliest AgTech companies created and deals mainly with satellite imagery analytics and distribution. Currently I write about the AgTech industry through my Easy Observations newsletter, performs business consulting in the Ag industry, and I have my own business called Boundri which provides tools for map based printed products from wall maps to farm toy play rugs.', 'https://www.linkedin.com/in/nathan-faleide-036b43b5', 'Indirectly - Most all that are directly related to precision ag data and services to some extent over the years. Directly - I''ve been selective in who I''ve engaged with and have only been into consulting the last year working with 4 different AgTech based groups.', 'Cash', 'Limited', 'US', 'US, but very close to Canada');
INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Olivier Harvey', 'consultant / www.greenridge.ch', 'Product Development and Management Expertise in launching new product lines, brand development, and portfolio management, aligning with market needs and regulatory compliance.  Strategic Marketing and Sales Proficient in creating and executing multi-channel marketing strategies, leading international marketing campaigns, and fostering customer engagement to drive significant market share growth.  Business Strategy and Expansion Skilled in crafting and implementing strategies for international expansion and scaling operations in diverse geopolitical environments.  Change Management Experienced in leading comprehensive business process overhauls that enhance organizational efficiency and responsiveness to market changes.  Investor Relations and Stakeholder Management Strong background in managing communications with investors, preparing for IPOs, and engaging stakeholders at all levels to support business objectives and sustainability goals.', 'Chemical and Biological Inputs  Market Expansion and Commercialization  Operational Efficiency and Integration / Scaling  Stakeholder Engagement and Investor Relations  Sustainability and Renewable Energy Solutions', '', 'Comprehensive Expertise & Experience: Strategic leadership in commercial marketing, communications, and operational excellence, Substantial growth in several high-impact roles within the agriculture chemical and renewable energy sectors.  Recent roles include:  VP Marketing & Communications, Northern Plains Nitrogen: Strategic advisor,  go-to-market strategies, secured a shortlist position for a significant government development loan, (carbon sequestration and renewable energy components).  Director of Marketing & Commercialization, Ductor: Dynamic commercialization strategies for pre-revenue organic fertilizer and biogas group.  Global Commercial Executive Leadership, EuroChem: Supported the company’s expansion from $3 billion to $12 billion in revenue. Marketing, Leadership, Integration and scaling, communications, investor relations, branding, product quality, customer engagement..  Led multiple initiatives improved operational efficiency and market engagement.  Skills: Multicultural Leadership and Cross-functional Team Management Strategic Market Expansion and Brand Positioning  Project Management and Change Management Stakeholder Engagement and Investor Relations', 'https://(1) Olivier Harvey | LinkedIn   https://www.linkedin.com/in/olivierharvey', 'From projects: Northern Plains Nitrogen (blue ammonia), Ductor (organic ferts), to large scale global production and distribution (EuroChem)', 'Open', 'Yes', 'US', 'Based in Switzerland, experience and network in Europe, Russia, Asia, US, Canada and Brazil.   Languages: English, French, Russian');
INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Pam Marrone', 'Invasive Species Corporation', 'raising money, IPOs, biologicals R&D, manufacturing, go to market. regulatory, M&A', 'biologicals inputs and tech as related', 'Specialty Crop (fruit/nut/veg)', 'Serial entrepreneur. Started and led three biologicals companies, all three sold to larger companies. Starting a 4th company now. Also serve as an advisor or board member to several startups. My time is limited so i cannot take on any more formal advisory roles but happy to help/mentor from time to time.', 'https://www.linkedin.com/in/pam-marrone-110ab6', 'Root Applied Sciences, Pheronym, Elicit Plant, Innatrix, Chonex, True Algae, Teneral Cellars, Spectral Analytix.', 'Open', 'Yes', 'US', 'Unknown');
INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Patrick Honcoop', 'AgTech-Pro', 'Market Entry Europe, Go-to-market strategy,  Growth strategy, Partnership development,  Competitive assessment, Value proposition,  market research', 'Digital Ag, FMIS, Equipment, Robotics, Automation, Sensors, Analytics', 'Midwest crops (corn/soy)', 'I have extensive experience in Europe and North America,  mainly focusing on arable crops, vegetables, and dairy. I have played a pivotal role in driving the success of the leading FMIS in Europe, known as 365FarmNet, and led digital strategy for  CLAAS in North America. I have provided guidance and support to various startups, assisting them in formulating effective go-to-market strategies, building impactful partnerships, and facilitating their expansion across the European and North American markets. My approach is rooted in pragmatism, seeking practical and feasible solutions.', 'https://www.linkedin.com/in/patrick-honcoop', 'VergeAg, Solinftec, UNIFORM-Agri,  BushelPlus and others confidential', 'Cash & Equity', 'Yes', 'US', 'Unknown');
