INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Sachi Desai', 'Bayer Crop Science', 'Strategy, Digital, Market Landscape, AgTech, AI/ML, Big Data, Networks, Cloud, Data Security, Hardware', 'Broadly Inputs, but more specifically around the interaction of agriculture/food and technology', 'Midwest crops (corn/soy)', 'Across my 20 years I''ve worked business of varying sizes at varying stages. In Agriculture, I co-lead the establishment and development of the first paid platform, FieldView Partner Platform that features a global ecosystem of over 80 partners to date. I built many of the pioneering business models to monetize cloud services, data services, and models in agriculture.  I was the leader for many of Bayer''s most innovative digital activities including the Bayer-Microsoft Partnership, the acquistion of Combyne, and the first Carbon Intensity Measuring program, CarbonView.  Prior to this I have deep experience in technology like Cloud, Big Data, AI, Machine Learning, IoT, Remote Sensing, etc., If it was a technology in the last 20 years I''ve been involved.', 'https://www.linkedin.com/in/sachivdesai', 'For past 6 years I''ve been collaborating, mentioring, engaging starts ups in the Agriculture space provding insight in how a large multinational thinks, how leading edge technology can be used and acting as a sounding board.', 'Open', 'Yes', 'US', 'USA');
INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Sandeep Ravula', 'Consultant', '1.        Scaling adoption of AgTech solutions in India & Africa  2.        IoT & sharing economy/aggregator business models for Farm equipment 3.        Farming as a service- full stack, phygital model for developing economies 4.        Localization and UX strategy & modalities for Digital apps facing small & medium landholding farmers in India & Africa. 5.        Subscription & pay-per-use business models. 6.        Stakeholder & channel partner navigation for products/service offering in India- How to position product/service partnerships to large companies & channel partners. 7.        AgTech Start-ups in India- who''s winning/whats working/building an investment thesis. 8.        Agristack, a Digital public infrastructure for Agriculture, Govt of India- how to get in? 9. Credit profiling & scoring farmers & tractor owners using alternate sources of data (apps & machines)', 'IoT, Mobile apps, precision Ag enterprise software, Digital Crop advisory, Hardware, Farm management Software', '', '1.        Ex World bank group – Senior consultant on the Agristack project by the Govt of India, working directly with the Chief knowledge officer (Ministry of Agriculture & Farmer welface) and the CEO of PM-Kisan programme. 2.        Founding team member & Head of Digital solutions business at Krish-e by Mahindra, a full stack farming as a service business 3.        Head of IoT & Emerging technology business at Mahindra & Mahindra.  4.        Head of BD & Strategic partnerships at Titan Smart Wearables group.  5.        Head of Business development at HealthifyMe wellness.  6.        Corp Strategy at Hewlett Packard USA & India', 'https://www.linkedin.com/in/sandeepravula', 'Carnot Technologies (IoT for farm equipment, apps for advisory); BharatRohan (hyperspectral drones); Agristack (Govt of India); Krish-e by Mahindra (full stack Faas)', 'Cash & Equity', 'Yes', 'IN', 'India');
