INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Stephanie Pharris', 'CNH Industrial - AGXTEND', 'Accelerating innovative solutions through strong product development partnerships with startup companies by leveraging CNH Industrial’s global spotlight, customer knowledge, product integration and distribution strengths.', 'Stage agnostic agriculture technologies - looking for solutions to solve challenges of labor shortage, safeguarding yields, creating farm efficiencies, improving sustainability, and supporting economic growth for farmers.', 'Specialty Crop (fruit/nut/veg)', '10+ years working in organic specialty crop production, leading ag-tech development projects and implementations, working with startups from POC to full scale market adoption, managing R&D projects related to farming/ag-tech, and product management within the ag-tech space.', '', 'Zasso, Apps for Agri, Dinamica Generale, Augmenta, Vermeulen, Agroplanning, Ucrop.IT, Cropman, Bemagro, CropScan Ag, MPT', 'Open', 'Yes', 'US', 'I am in the US, but my team is global; EU, ANZ, LATAM, NAFTA');
