INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Thea Gherdan', 'The C-fit Group', 'Sales & Revenue Operations & Sales teams, Startup Scale-up', 'Sales Processes optimisation & revenue streams', 'Agro Chemical', 'Chief-Revenue-Officer-as-a-Service for agritech startups with 10+years in People Operations & building sales teams, 6+ years in B2B Sales Operations, 6+ years in agriculture & agritech.', '', 'Conservation & Sustainability Aquaculture Plant Protection Products encapsulation Alternative fuel - Gasification technology  Livestock / animal nutrition Biorefinery Livestock / environmental monitoring solution Carbon farming Livestock / animal automatic tracking  Carbon farming & regenerative agriculture platform Remote sensing-based modeling for regenerative agriculture Neural network models for detecting field boundaries Independent Precision Agriculture Platform Livestock / Smart Stockbreeding Biodegradable materials alternative to plastic', 'Cash & Equity', 'Limited', 'US', 'Unknown');
INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Tim Bishop', 'Hudson Sonoma', 'Product strategy, development, engineering of sensor hardware. Deciding what tech to build is hard.  As a way of quickly exploring I can 1) help you build a sensor hardware prototype fast by building on top of existing open hardware projects, and 2) help you host a few workshops with a small group of your key supporters and contributors to plan and develop your simple but awesome MVP', 'Sensor hardware for production or animal use. Product workshops. Also simple solutions for firmware, backend, AI, apps.', 'Specialty Crop (fruit/nut/veg)', 'I have 10 years of experience working for startups and helping them build their first prototypes and MVPs. I have developed sensor systems for wineries and for veterinary use and coordinated strategy workshops. I''m always open for a call at hudson-sonoma.com.', 'https://www.linkedin.com/in/timbishophs', 'Winely, Ingenum, Working Formula, Goat Rock, HeartSense, BuildingPULSE', 'Cash & Equity', 'Yes', 'US', 'USA, New Zealand');
INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Tim Nuss', 'Nuss Farms, Inc.', 'Fresh produce supply chains, production agriculture, agtech business development and category sales', 'I manage a wide range of focus areas for my family''s farming operation. We''re focused on agtech tools to address labor (weeding and harvest), agronomy, custom application, and soil resilience. We grow a variety of crops - garlic, processing tomatoes, peppers, melons, herbs, etc. all with varied irrigation, logistics, and agronomic demands.', 'Specialty Crop (fruit/nut/veg)', 'After spending close to a decade in the fresh produce industry focused on international exports and several years in agtech (most recently with Apeel Sciences) I returned to the family farm in late 2022. I oversee sales, business development, legal, agtech adoption, business operations, and back office systems. We farm a range of fruit and vegetable crops in Lodi, California. I also co-host The Modern Acre podcast, a weekly podcast focused on innovation in food and agriculture.', 'https://www.linkedin.com/in/timnuss', 'Under NDA', 'Open', 'Yes', 'US', 'Unknown');
INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Todd Linsky', 'TLC', 'Sales, Marketing, Brand Management, Leadership Teams', 'Brands, People and Purpose', 'Specialty Crop (fruit/nut/veg)', 'Advising investors, start-ups, retailers and growers in the area of soil,farmed fruits and vegetables, vertical farming, aeroponics, greenhouse containers farms,aquaponics,medical cannabis and hemp', 'http://linkedin.com/in/todd-linsky-81a6804a', 'Worked with over 50 companies globally over the past 8 years building brands and the teams that make them fly. All of my clients are under NDA''s', 'Open', 'Yes', 'US', 'USA');
INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Walter Paulsen', 'Coach, Vistage Chair', 'CEO and Leadershp coach for high growth companies.  Work primarily with founders, CEOs and executive teams on growth strategies, Leadership and Team building, rapid scaling, fund raising.', 'AgTech speciality crops, greenhouse automation, fertigation, robotics, Primarily Seed stage through Series A/B', 'Specialty Crop (fruit/nut/veg)', 'CEO with multiple successful exits.  Co-founder of nutrient control system for indoor and greenhouse farming. Coach CEOs of indoor farming, robotics, computer vision, SaaS and many others.   Leading a company is hard and lonely.  I''ve been there multiple times myself, myu mission is to  help CEOs be their best selves and achieve their life''s work.', 'https://www.linkedin.com/in/walterpaulsen', 'Magnolia Farms (Vertical farming), Tric Robotics, (UV robots for strawberry farming), Agerpix (Spanish HQ, computer vision for fruit trees), plus many software, Fintech and other growth companies', 'Cash & Equity', 'Yes', 'US', 'USA');
