INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Bill Glover', 'Procrastes Press', 'Ghostwriting - I help agTech startups build value and close more deals by educating customers and investors, building thought leadership, and creating engaged communities.', 'As an engineer, I can help explain complex concepts in accessible ways while offering deep insight into technical product development and efficiencies especially in typically harsh Ag field conditions.', 'Livestock / Dairy', '30+ years in technology and agriculture as a software engineer while writing technical and popular non fiction. Former startup mentor for the WIRE accelerator program at West Texas A&M University Enterprise Center.', 'https://www.linkedin.com/in/billglover', 'Truckl, Plan-It, Compare-That, Jobsist, LearnLounge, and many others.', 'Cash', 'Yes', 'US', 'USA');
INSERT INTO public.mentors (name, firm, expertise, focus_areas, ag_expertise, experience, linkedin, startups_worked_with, compensation, available, country, country_detail) VALUES ('Raja Ramachandran', 'Independent, ex Ripe.io CEO, DoubleZero Holdings', 'Ag and food start up, capital raise strategy, blockchain expertise, food traceability regulatory and compliance, food safety, digital supply chains in food and ag, DNA and genetics use in identifying livestock along with growth characteristics, dMRV systems, currently involved in funding and managing GHG reduction projects for renewable energy and commodities specifically blue and green, biochar and sustainable aviation fuel. Well versed in all aspects of food traceability from farm to fork and including pre and post harvest.', 'Can provide technical, product and financial advisory for the earliest stages of digital product and platform formation, to helping manage start ups from "0 to 1", leverage GHG credits as supplemental revenue sources where it makes sense, supply chain design and management leveraging blockchain', 'Livestock / Dairy', 'Created and sold 3 start ups in instituational financial trading, retail energy and digital food supply management. Long time financial institutaional experience in trading and capital markets, venture capital raise strategy, go to market strategies, fixer upper for early stage companies, blockchain expertise, technology and product strategy/build.', 'https://www.linkedin.com/in/raja-ramachandran-14a20', 'Companies I''ve started and managed as either CEO or COO - Pfn, Chooseenergy.com, ripe.io. Advisor for TransparencyWise, couple of stealth start ups in AI', 'Cash & Equity', 'Yes', 'US', 'USA');